88	export function claim(
89	  items: Item[],
90	  damages: Damage[],
91	  previousPaid: number = 0,
92	): { payout: number; remainingCap: number } {
93	  const itemCounts: Record<string, number> = {};
94	  for (const item of items) {
95	    itemCounts[item.type] = (itemCounts[item.type] ?? 0) + 1;
96	  }
97	  const damageCounts: Record<string, number> = {};
98	  for (const damage of damages) {
99	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
100	  }
101	  for (const [type, count] of Object.entries(damageCounts)) {
102	    if (count > (itemCounts[type] ?? 0)) {
103	      throw new Error(`damage count exceeds insured count for type ${type}`);
104	    }
105	  }
106	  const totalPayout = damages.reduce((sum, damage) => {
107	    const item = items.find((i) => i.type === damage.itemType);
108	    const reimbursed = reimbursementAmount(item, damage.amount);
109	    return sum + Math.max(0, reimbursed - DEDUCTIBLE);
110	  }, 0);
111	  const insuranceSum = items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
112	  const cap = CAP_MULTIPLIER * insuranceSum;
113	  const capRemainingBeforeClaim = cap - previousPaid;
114	  const cappedPayout = Math.min(Math.floor(totalPayout), capRemainingBeforeClaim);
115	  return { payout: cappedPayout, remainingCap: capRemainingBeforeClaim - cappedPayout };
116	}
117	
118	export function quote(customer: Customer, items: Item[]): number {
119	  const countsByType: Record<string, number> = {};
120	  for (const item of items) {
121	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
122	  }
123	
124	  const policyBase = Object.entries(countsByType)
125	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
126	
127	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
128	  const loyalty = loyaltyDiscount(customer, policyBase);
129	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
130	  const followup = followupDiscount(customer, policyBase);
131	
132	  return Math.ceil(policyBase + itemSurcharges - loyalty + firstInsurance - followup) + PROCESSING_FEE;
133	}
